/**
 * Emitted when a CRITICAL-severity drift or user-steer triggers
 * cooperative cancellation of an agent invocation. Operator-visible
 * marker — the LLM sees only ``{"status": "cancelled"}`` as the
 * sub-invocation's return value (see goldfive#251 Stream C). The
 * rich operator-side context (reason, severity, drift_id, drift_kind,
 * detail, tool_name) lives ONLY on this sink event so it cannot leak
 * into the parent agent's transcript and bias its next turn.
 *
 * Promoted from a dict envelope to a typed proto message (Stream C
 * shipped the dict shape to avoid proto-regen scope-creep; #187 then
 * added a placeholder ``harmonograf.v1.InvocationCancelled`` for
 * ingest). Harmonograf-side migration onto this typed message is a
 * separate Wave 2 PR (submodule bump).
 *
 * @generated from message goldfive.v1.InvocationCancelled
 */
export type InvocationCancelled = Message<"goldfive.v1.InvocationCancelled"> & {
  /**
   * ADK ``invocation_id`` of the dispatch that was cancelled.
   *
   * @generated from field: string invocation_id = 1;
   */
  invocationId: string;

  /**
   * Agent the invocation was running, when known. Empty when the
   * cancel fired before the agent identity was resolvable (e.g. on
   * the ``before_run_callback`` checkpoint).
   *
   * @generated from field: string agent_name = 2;
   */
  agentName: string;

  /**
   * Short symbolic reason — ``"drift"`` / ``"user_steer"`` /
   * ``"plan_revised"`` / etc. Free-form string; consumers pattern-
   * match prefixes when useful.
   *
   * @generated from field: string reason = 3;
   */
  reason: string;

  /**
   * Severity of the triggering drift, lowercased: ``"info"`` /
   * ``"warning"`` / ``"critical"``. Empty when no drift origin
   * (programmatic cancels). Recorded as a string (not the
   * ``DriftSeverity`` enum) so consumers can render it without an
   * enum lookup.
   *
   * @generated from field: string severity = 4;
   */
  severity: string;

  /**
   * Cross-reference to the triggering ``DriftEvent.id`` when the
   * cancel was minted from a drift. Empty for user-control cancels
   * or programmatic calls with no drift origin.
   *
   * @generated from field: string drift_id = 5;
   */
  driftId: string;

  /**
   * Drift kind as the bare lowercase string (e.g. ``"off_topic"``).
   * Optional. Empty when no drift origin.
   *
   * @generated from field: string drift_kind = 6;
   */
  driftKind: string;

  /**
   * Human-readable one-line description of why cancel fired.
   * Operator-visible only; never reaches the LLM.
   *
   * @generated from field: string detail = 7;
   */
  detail: string;

  /**
   * Tool name when the cancel checkpoint fired in
   * ``before_tool_callback`` (a tool-dispatch was about to run and
   * was short-circuited). Empty for cancels detected at
   * ``before_agent_callback`` / ``before_model_callback`` where no
   * specific tool was in flight.
   *
   * @generated from field: string tool_name = 8;
   */
  toolName: string;
};

